### 3. Create `Services/CatalogService.cs` — an in-memory data service:

```csharp
namespace UniversityCourseCatalog.Services;

using UniversityCourseCatalog.Models;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS 101", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented programming basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace has 15 years of experience teaching introductory programming and is passionate about making computer science accessible to all students.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", CourseCode = "CS 201", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing is a renowned researcher in algorithm optimization with publications in top-tier journals.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", CourseCode = "CS 305", Description = "Design and implementation of database systems. Covers relational model, SQL, normalization, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Edgar Codd", InstructorBio = "Dr. Codd specializes in distributed database systems and has industry experience at major tech companies.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Isaac Newton", InstructorBio = "Dr. Newton brings calculus to life with real-world applications and has won multiple teaching awards.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH 220", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether is an expert in abstract algebra with a focus on making complex mathematical concepts intuitive.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "General Physics I", CourseCode = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Richard Feynman", InstructorBio = "Dr. Feynman is known for his engaging lecture style and ability to explain complex physics concepts simply.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 7, Title = "Quantum Mechanics", CourseCode = "PHYS 301", Description = "Introduction to quantum theory, wave functions, Schrödinger equation, and quantum measurement.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Niels Bohr", InstructorBio = "Dr. Bohr has published extensively on quantum computing applications and mentors graduate researchers.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 8, Title = "English Composition", CourseCode = "ENG 101", Description = "Develop writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Maya Angelou", InstructorBio = "Dr. Angelou is a published author who brings creative writing expertise to academic composition.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Title = "American Literature", CourseCode = "ENG 250", Description = "Survey of American literary works from colonial period to the present.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Mark Twain", InstructorBio = "Dr. Twain specializes in 19th-century American literature and brings humor to literary analysis.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "World History", CourseCode = "HIST 101", Description = "Survey of world civilizations from ancient times to the modern era.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Howard Zinn", InstructorBio = "Dr. Zinn emphasizes primary sources and encourages students to examine history from multiple perspectives.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetAllCourses() => _courses;
}
