**Components/Pages/Enroll.razor:**
```razor
@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p class="text-muted">Submit your enrollment request below. You will be contacted by the registrar's office.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been submitted successfully.</p>
        <hr />
        <p class="mb-0">The registrar's office will process your request and contact you at your university email.</p>
    </div>
    <a href="/courses" class="btn btn-secondary">Browse More Courses</a>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <form method="post" class="needs-validation">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
                    <ValidationMessage For="() => Model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" placeholder="e.g., STU-12345" required />
                    <ValidationMessage For="() => Model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select id="courseId" name="Model.CourseId" class="form-select" required>
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in CatalogService.GetAllCourses())
                        {
                            <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode - @course.Title</option>
                        }
                    </select>
                    <ValidationMessage For="() => Model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

