}
else
{
    <PageTitle>@course.Title - University Course Catalog</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.Title</h1>
            <p class="text-muted fs-5">@course.CourseCode &middot; @course.DepartmentName</p>

            <section class="mb-4">
                <h2>Description</h2>
                <p>@course.Description</p>
            </section>

            <section class="mb-4">
                <h2>Schedule</h2>
                <p><strong>@course.Schedule</strong></p>
            </section>

            <section class="mb-4">
                <h2>Instructor</h2>
                <h5>@course.InstructorName</h5>
                <p>@course.InstructorBio</p>
            </section>
        </div>

        <div class="col-lg-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <ul class="list-unstyled">
                        <li class="mb-2"><strong>Credits:</strong> @course.Credits</li>
                        <li class="mb-2"><strong>Department:</strong> @course.DepartmentName</li>
                        <li class="mb-2"><strong>Code:</strong> @course.CourseCode</li>
                    </ul>
                    <a href="/enroll?courseId=@course.Id" class="btn btn-primary w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

